#!/usr/bin/env bash
# Self-contained installer for web-artifacts-builder and skill-creator skills
# Target: ~/.claude/skills/ on Windows Git Bash (HOME=/c/Users/dvirm)
set -e

DEST="$HOME/.claude/skills"
echo "Installing skills to $DEST ..."

mkdir -p "$DEST/skill-creator"
mkdir -p "$DEST/skill-creator/agents"
mkdir -p "$DEST/skill-creator/assets"
mkdir -p "$DEST/skill-creator/eval-viewer"
mkdir -p "$DEST/skill-creator/references"
mkdir -p "$DEST/skill-creator/scripts"
mkdir -p "$DEST/web-artifacts-builder"
mkdir -p "$DEST/web-artifacts-builder/scripts"

echo "  Writing web-artifacts-builder/SKILL.md ..."
printf '%s' '' | base64 -d > "$DEST/web-artifacts-builder/SKILL.md"

echo "  Writing web-artifacts-builder/LICENSE.txt ..."
printf '%s' '' | base64 -d > "$DEST/web-artifacts-builder/LICENSE.txt"

echo "  Writing web-artifacts-builder/scripts/init-artifact.sh ..."
printf '%s' '' | base64 -d > "$DEST/web-artifacts-builder/scripts/init-artifact.sh"

echo "  Writing web-artifacts-builder/scripts/bundle-artifact.sh ..."
printf '%s' '' | base64 -d > "$DEST/web-artifacts-builder/scripts/bundle-artifact.sh"

echo "  Writing web-artifacts-builder/scripts/shadcn-components.tar.gz ..."
printf '%s' '' | base64 -d > "$DEST/web-artifacts-builder/scripts/shadcn-components.tar.gz"

echo "  Writing skill-creator/SKILL.md ..."
printf '%s' '' | base64 -d > "$DEST/skill-creator/SKILL.md"

echo "  Writing skill-creator/LICENSE.txt ..."
printf '%s' '' | base64 -d > "$DEST/skill-creator/LICENSE.txt"

echo "  Writing skill-creator/agents/analyzer.md ..."
printf '%s' '' | base64 -d > "$DEST/skill-creator/agents/analyzer.md"

echo "  Writing skill-creator/agents/comparator.md ..."
printf '%s' '' | base64 -d > "$DEST/skill-creator/agents/comparator.md"

echo "  Writing skill-creator/agents/grader.md ..."
printf '%s' '' | base64 -d > "$DEST/skill-creator/agents/grader.md"

echo "  Writing skill-creator/assets/eval_review.html ..."
printf '%s' '' | base64 -d > "$DEST/skill-creator/assets/eval_review.html"

echo "  Writing skill-creator/eval-viewer/generate_review.py ..."
printf '%s' '' | base64 -d > "$DEST/skill-creator/eval-viewer/generate_review.py"

echo "  Writing skill-creator/eval-viewer/viewer.html ..."
printf '%s' '' | base64 -d > "$DEST/skill-creator/eval-viewer/viewer.html"

echo "  Writing skill-creator/references/schemas.md ..."
printf '%s' '' | base64 -d > "$DEST/skill-creator/references/schemas.md"

echo "  Writing skill-creator/scripts/__init__.py ..."
printf '%s' '' | base64 -d > "$DEST/skill-creator/scripts/__init__.py"

echo "  Writing skill-creator/scripts/aggregate_benchmark.py ..."
printf '%s' '' | base64 -d > "$DEST/skill-creator/scripts/aggregate_benchmark.py"

echo "  Writing skill-creator/scripts/generate_report.py ..."
printf '%s' '' | base64 -d > "$DEST/skill-creator/scripts/generate_report.py"

echo "  Writing skill-creator/scripts/improve_description.py ..."
printf '%s' '' | base64 -d > "$DEST/skill-creator/scripts/improve_description.py"

echo "  Writing skill-creator/scripts/package_skill.py ..."
printf '%s' '' | base64 -d > "$DEST/skill-creator/scripts/package_skill.py"

echo "  Writing skill-creator/scripts/quick_validate.py ..."
printf '%s' '' | base64 -d > "$DEST/skill-creator/scripts/quick_validate.py"

echo "  Writing skill-creator/scripts/run_eval.py ..."
printf '%s' '' | base64 -d > "$DEST/skill-creator/scripts/run_eval.py"

echo "  Writing skill-creator/scripts/run_loop.py ..."
printf '%s' '' | base64 -d > "$DEST/skill-creator/scripts/run_loop.py"

echo "  Writing skill-creator/scripts/utils.py ..."
printf '%s' '' | base64 -d > "$DEST/skill-creator/scripts/utils.py"

chmod +x "$DEST/web-artifacts-builder/scripts/init-artifact.sh"
chmod +x "$DEST/web-artifacts-builder/scripts/bundle-artifact.sh"

echo ""
echo "Done! Installed skills:"
echo "  - web-artifacts-builder  (React/shadcn/ui HTML artifact builder)"
echo "  - skill-creator          (create, test, and optimize Claude skills)"
echo ""
echo "Restart Claude Code for skills to be picked up."
